import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Package, ArrowRight } from 'lucide-react';
import { orderAPI } from '../api/api';

export default function OrdersPage() {
  const [orders, setOrders] = useState([]);
  const [stats, setStats] = useState({ totalOrders: 0, pendingOrders: 0, shippedOrders: 0, deliveredOrders: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([orderAPI.getAll(), orderAPI.getStats()])
      .then(([ordRes, statRes]) => {
        setOrders(ordRes.data.data || []);
        setStats(statRes.data.data || stats);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const statusBadge = (status) => {
    const map = { PENDING: 'badge-warning', CONFIRMED: 'badge-accent', PROCESSING: 'badge-accent', SHIPPED: 'badge-accent', OUT_FOR_DELIVERY: 'badge-warning', DELIVERED: 'badge-success', CANCELLED: 'badge-danger', RETURNED: 'badge-danger' };
    return <span className={`badge ${map[status] || 'badge-accent'}`}>{status.replace(/_/g, ' ')}</span>;
  };

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;

  return (
    <div className="page-container">
      <h1 className="page-title">My Orders</h1>

      <div className="orders-stats">
        {[
          { label: 'Total', value: stats.totalOrders, color: 'var(--text-primary)' },
          { label: 'Pending', value: stats.pendingOrders, color: 'var(--warning)' },
          { label: 'Shipped', value: stats.shippedOrders, color: 'var(--accent)' },
          { label: 'Delivered', value: stats.deliveredOrders, color: 'var(--success)' },
        ].map(s => (
          <div key={s.label} className="stat-card">
            <div className="stat-number" style={{ color: s.color }}>{s.value}</div>
            <div className="stat-label">{s.label}</div>
          </div>
        ))}
      </div>

      {orders.length === 0 ? (
        <div className="cart-empty">
          <Package size={56} color="var(--text-muted)" />
          <h2>No orders yet</h2>
          <p>Start shopping to place your first order.</p>
          <Link to="/products" className="btn btn-primary">Browse Products</Link>
        </div>
      ) : (
        orders.map(order => (
          <div key={order.id} className="order-card">
            <div className="order-card-header">
              <div>
                <span className="order-number">{order.orderNumber}</span>
                <span className="order-date" style={{ marginLeft: 16 }}>{new Date(order.createdAt).toLocaleDateString()}</span>
              </div>
              {statusBadge(order.status)}
            </div>
            <div className="order-card-body">
              <div className="order-items-list">
                {order.items?.slice(0, 3).map(item => (
                  <div key={item.id} className="order-item-row">
                    <img src={item.productImage} alt={item.productName} className="order-item-img" />
                    <div className="order-item-details">
                      <div className="order-item-name">{item.productName}</div>
                      <div className="order-item-qty">Qty: {item.quantity}</div>
                    </div>
                    <span className="order-item-price">${item.lineTotal?.toFixed(2)}</span>
                  </div>
                ))}
                {order.items?.length > 3 && (
                  <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>+{order.items.length - 3} more items</p>
                )}
              </div>
            </div>
            <div className="order-card-footer">
              <span className="order-total">Total: ${order.total?.toFixed(2)}</span>
              <Link to={`/orders/${order.id}`} className="btn btn-secondary btn-sm">
                View Details <ArrowRight size={14} />
              </Link>
            </div>
          </div>
        ))
      )}
    </div>
  );
}
